import json
from pathlib import Path

import pytest

AC_UID = "f1b0a0e412786b6a"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TARGET = REPO_ROOT / "policies" / "tool-policy.v1.json"

NEW_PREFIX = "*/.claude/dev-registry/*/blast-radius-map.json"
PRESERVED_PREFIX = "*/docs/dev/acceptance-criteria-"
EXPECTED_VERSION = 5
NOTE_SUBSTRINGS = ["policy_version 5", "blast-radius-map"]


def test_AC_08():
    """
    GIVEN: policies/tool-policy.v1.json is parsed as JSON
    WHEN:  .roles.ba.allowed_write_path_prefixes and .policy_version are queried via jq
    THEN:  jq index for '*/.claude/dev-registry/*/blast-radius-map.json' returns non-null integer; jq index for '*/docs/dev/acceptance-criteria-' returns non-null integer (preservation check); policy_version equals 5 (live baseline 4 + 1); _note field is extended with paragraph mentioning policy_version 5 and BA blast-radius prefix
    """
    assert TARGET.exists(), f"{TARGET} missing"
    policy = json.loads(TARGET.read_text(encoding="utf-8"))

    # policy_version
    assert policy.get("policy_version") == EXPECTED_VERSION, (
        f"policy_version expected {EXPECTED_VERSION}; got {policy.get('policy_version')!r}"
    )

    prefixes = (
        policy.get("roles", {}).get("ba", {}).get("allowed_write_path_prefixes", [])
    )
    assert isinstance(prefixes, list), "roles.ba.allowed_write_path_prefixes not a list"

    # New BA blast-radius prefix
    assert NEW_PREFIX in prefixes, (
        f"BA allowed_write_path_prefixes missing new entry {NEW_PREFIX!r}\n"
        f"present prefixes: {prefixes}"
    )
    new_idx = prefixes.index(NEW_PREFIX)
    assert isinstance(new_idx, int) and new_idx >= 0

    # Preservation check — the existing acceptance-criteria prefix must remain
    assert PRESERVED_PREFIX in prefixes, (
        f"Preservation violated: {PRESERVED_PREFIX!r} not in BA prefixes"
    )

    # _note field extension
    note = policy.get("_note", "")
    assert isinstance(note, str) and note, "_note missing or non-string"
    for sub in NOTE_SUBSTRINGS:
        assert sub in note, f"_note missing required substring {sub!r}"
